+    {
+      label: 'Select Split',
+      icon: '◫',
+      disabled: !hasTabs,
+      submenu: [
+        { label: 'Select Split Above', action: '_select_split_up', shortcut: '⌘⇧↑', icon: '↑', disabled: !hasTabs },
