+        const panel = muxClient?.getActivePanel();
+        if (panel) muxClient?.splitPanel(panel, 'down');
+        break;
+      }
+      case '_split_left': {
+        const panel = muxClient?.getActivePanel();
+        if (panel) muxClient?.splitPanel(panel, 'left');
